"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[849],{4849:function(e,a,i){i.d(a,{Hs:function(){return t},g_:function(){return l},kg:function(){return o},pG:function(){return n}});let t={vascular:"Vascular",abdomen:"Abdomen",ob:"OB/GYN",thyroid:"Thyroid",cardiac:"Cardiac",musculoskeletal:"MSK",superficial:"Superficial"},n={vascular:"bg-red-100 text-red-700 border-red-200",abdomen:"bg-amber-100 text-amber-700 border-amber-200",ob:"bg-pink-100 text-pink-700 border-pink-200",thyroid:"bg-purple-100 text-purple-700 border-purple-200",cardiac:"bg-blue-100 text-blue-700 border-blue-200",musculoskeletal:"bg-green-100 text-green-700 border-green-200",superficial:"bg-teal-100 text-teal-700 border-teal-200"},o=[{id:"aorta-diameter",name:"Abdominal Aorta Diameter",category:"vascular",subcategory:"Aorta",ranges:[{max:3,unit:"cm",label:"Normal (AP diameter)"},{min:3,max:5.4,unit:"cm",label:"Aneurysm (AAA)",notes:"Monitor with ultrasound"},{min:5.5,unit:"cm",label:"Surgical threshold",notes:"Refer to vascular surgery"}],clinicalNote:"Measure outer wall to outer wall in AP plane. AAA defined as >3.0 cm or 1.5\xd7 the normal diameter.",tags:["aorta","aaa","aneurysm","vascular","abdominal"]},{id:"carotid-imt",name:"Carotid IMT (Intima-Media Thickness)",category:"vascular",subcategory:"Carotid",ranges:[{max:.9,unit:"mm",label:"Normal"},{min:.9,max:1.5,unit:"mm",label:"Borderline / Early atherosclerosis"},{min:1.5,unit:"mm",label:"Plaque present",notes:"Significant atherosclerotic burden"}],clinicalNote:"Measure far wall of CCA, 1 cm proximal to bifurcation. Use high-frequency linear transducer.",tags:["carotid","imt","intima-media","atherosclerosis","cca"]},{id:"carotid-psv",name:"Carotid PSV (ICA)",category:"vascular",subcategory:"Carotid",ranges:[{max:125,unit:"cm/s",label:"Normal ICA PSV (<50% stenosis)"},{min:125,max:229,unit:"cm/s",label:"50–69% stenosis"},{min:230,unit:"cm/s",label:"≥70% stenosis",notes:"Consider surgical intervention"}],clinicalNote:"SRU/SVU consensus criteria. Also check ICA:CCA ratio (>4 = >70% stenosis). Angle ≤60\xb0.",tags:["carotid","ica","psv","stenosis","doppler","velocity"]},{id:"carotid-ica-cca-ratio",name:"ICA/CCA PSV Ratio",category:"vascular",subcategory:"Carotid",ranges:[{max:2,unit:"ratio",label:"Normal (<50% stenosis)"},{min:2,max:4,unit:"ratio",label:"50–69% stenosis"},{min:4,unit:"ratio",label:"≥70% stenosis"}],clinicalNote:"Used in conjunction with ICA PSV for stenosis grading.",tags:["carotid","ica","cca","ratio","stenosis"]},{id:"vertebral-artery-flow",name:"Vertebral Artery Direction",category:"vascular",subcategory:"Carotid",ranges:[{label:"Normal",unit:"direction",notes:"Antegrade (toward brain)"}],clinicalNote:"Retrograde flow = subclavian steal syndrome. Confirm with arm exercise provocative test.",tags:["vertebral","subclavian","steal","retrograde"]},{id:"portal-vein-diameter",name:"Portal Vein Diameter",category:"vascular",subcategory:"Abdominal Veins",ranges:[{max:13,unit:"mm",label:"Normal"},{min:13,unit:"mm",label:"Portal hypertension concern",notes:"Correlate with clinical findings"}],clinicalNote:"Measure at hepatic hilum. Respiratory variation normally present. Absent phasicity → consider hepatic/cardiac disease.",tags:["portal","vein","portal hypertension","liver","hepatic"]},{id:"portal-vein-velocity",name:"Portal Vein Velocity",category:"vascular",subcategory:"Abdominal Veins",ranges:[{min:15,max:40,unit:"cm/s",label:"Normal (hepatopetal flow)"},{max:15,unit:"cm/s",label:"Slow flow — portal HTN concern"}],clinicalNote:"Hepatofugal (away from liver) flow is pathological — suggests severe portal hypertension.",tags:["portal","vein","velocity","hepatopetal","portal hypertension"]},{id:"renal-artery-rai",name:"Renal Artery Resistive Index (RI)",category:"vascular",subcategory:"Renal",ranges:[{min:.58,max:.7,unit:"RI",label:"Normal"},{min:.7,max:.8,unit:"RI",label:"Mildly elevated — medical renal disease"},{min:.8,unit:"RI",label:"Significantly elevated — obstruction / rejection",notes:"In transplant: consider rejection"}],clinicalNote:"RI = (PSV - EDV) / PSV. Measure in 3 locations: upper, mid, lower pole. Average.",tags:["renal","kidney","resistive index","ri","doppler"]},{id:"renal-artery-psv",name:"Renal Artery PSV",category:"vascular",subcategory:"Renal",ranges:[{max:180,unit:"cm/s",label:"Normal"},{min:180,unit:"cm/s",label:"Renal artery stenosis concern",notes:"RAR >3.5 confirms significant stenosis"}],clinicalNote:"Renal-Aortic Ratio (RAR) = Renal PSV / Aortic PSV. RAR >3.5 = hemodynamically significant stenosis.",tags:["renal","artery","psv","stenosis","doppler"]},{id:"abi",name:"Ankle-Brachial Index (ABI)",category:"vascular",subcategory:"Peripheral Arterial",ranges:[{min:1,max:1.4,unit:"ratio",label:"Normal"},{min:.91,max:.99,unit:"ratio",label:"Borderline"},{min:.41,max:.9,unit:"ratio",label:"Mild–moderate PAD"},{max:.4,unit:"ratio",label:"Severe PAD / critical ischemia"},{min:1.4,unit:"ratio",label:"Non-compressible vessels (calcification)",notes:"Consider toe-brachial index"}],clinicalNote:"ABI = Ankle systolic / Brachial systolic (highest arm). Use highest ankle pressure (DP or PT).",tags:["abi","ankle-brachial","pad","peripheral arterial","doppler"]},{id:"liver-span",name:"Liver Span",category:"abdomen",subcategory:"Liver",ranges:[{min:13,max:17,unit:"cm",label:"Normal (mid-clavicular line, AP)"},{min:17,unit:"cm",label:"Hepatomegaly"},{max:13,unit:"cm",label:"Small liver — cirrhosis concern"}],clinicalNote:"Measure craniocaudal length in mid-clavicular line. Surface echotexture: normally smooth, homogeneous.",tags:["liver","hepatomegaly","span","cirrhosis","abdomen"]},{id:"spleen-length",name:"Spleen Length",category:"abdomen",subcategory:"Spleen",ranges:[{max:12,unit:"cm",label:"Normal"},{min:12,max:15,unit:"cm",label:"Mild splenomegaly"},{min:15,unit:"cm",label:"Moderate–severe splenomegaly"}],clinicalNote:"Measure longest axis in coronal plane. Thickness >4 cm alone can indicate splenomegaly.",tags:["spleen","splenomegaly","portal hypertension","abdomen"]},{id:"gallbladder-wall",name:"Gallbladder Wall Thickness",category:"abdomen",subcategory:"Gallbladder",ranges:[{max:3,unit:"mm",label:"Normal (fasting)"},{min:3,unit:"mm",label:"Thickened — cholecystitis, hepatitis, other",notes:"Must correlate with clinical (Murphy's sign, fever)"}],clinicalNote:"Measure anterior wall when fasting ≥4h. Diffuse thickening: also consider hypoalbuminemia, CHF, hepatitis.",tags:["gallbladder","wall","cholecystitis","murphy","abdomen"]},{id:"common-bile-duct",name:"Common Bile Duct (CBD) Diameter",category:"abdomen",subcategory:"Biliary",ranges:[{max:6,unit:"mm",label:"Normal (non-dilated)"},{max:8,unit:"mm",label:"Acceptable post-cholecystectomy"},{min:7,unit:"mm",label:"Dilated — obstruction/cholangiopathy concern"},{label:"+1 mm/decade >60 yrs",unit:"rule",notes:"Age-adjusted: up to 10 mm may be acceptable"}],clinicalNote:"Measure at porta hepatis, inner wall to inner wall. Always report with maximum diameter.",tags:["cbd","bile duct","biliary","obstruction","gallstone"]},{id:"kidney-size",name:"Kidney Length",category:"abdomen",subcategory:"Kidneys",ranges:[{min:9,max:12,unit:"cm",label:"Normal adult"},{max:9,unit:"cm",label:"Small — chronic renal disease"},{min:13,unit:"cm",label:"Large — hydronephrosis, polycystic, lymphoma"}],clinicalNote:"Normal cortical thickness ≥1.5 cm. Increased echogenicity = medical renal disease. Asymmetry >2 cm is clinically significant.",tags:["kidney","renal","hydronephrosis","pyelonephritis","size"]},{id:"bladder-post-void",name:"Post-Void Residual (PVR)",category:"abdomen",subcategory:"Bladder",ranges:[{max:50,unit:"mL",label:"Normal (adequate emptying)"},{min:100,max:299,unit:"mL",label:"Elevated — consider urinary retention workup"},{min:300,unit:"mL",label:"Significant retention",notes:"Correlate with symptoms"}],clinicalNote:"Volume = 0.52 \xd7 L \xd7 W \xd7 H (ellipsoid formula). Scan within 10 minutes of voiding.",tags:["bladder","pvr","post-void","retention","urinary"]},{id:"pancreas-duct",name:"Pancreatic Duct Diameter",category:"abdomen",subcategory:"Pancreas",ranges:[{max:3,unit:"mm",label:"Normal (body)"},{min:3,unit:"mm",label:"Dilated — pancreatitis, malignancy concern"}],clinicalNote:"Wirsungian duct visible in ~75% of patients. Beaded appearance with side branch involvement → IPMN concern.",tags:["pancreas","duct","wirsungian","pancreatitis","ipmn"]},{id:"uterus-length",name:"Uterine Length",category:"ob",subcategory:"Uterus",ranges:[{min:7,max:9,unit:"cm",label:"Normal reproductive-age (non-gravid)"},{max:7,unit:"cm",label:"Small — consider hypogonadism, prepubertal"},{min:10,unit:"cm",label:"Enlarged — fibroids, adenomyosis, pregnancy"}],clinicalNote:"Measure fundus to cervix (long axis). Width 4–6 cm, AP 3–5 cm normal. Postmenopausal: 3.5–6.5 cm.",tags:["uterus","uterine","fibroids","adenomyosis","gynecology"]},{id:"endometrium",name:"Endometrial Thickness",category:"ob",subcategory:"Uterus",ranges:[{max:4,unit:"mm",label:"Postmenopausal normal (no HRT)",notes:"Biopsy if >4 mm with bleeding"},{min:8,max:14,unit:"mm",label:"Secretory phase (premenopausal)"},{min:4,max:8,unit:"mm",label:"Proliferative phase"},{max:4,unit:"mm",label:"Menstrual / early proliferative"}],clinicalNote:"Measure double-layer (both layers) in sagittal plane. Post-menopausal bleeding + >4 mm → biopsy.",tags:["endometrium","endometrial","postmenopausal","bleeding","gynecology"]},{id:"ovary-size",name:"Ovary Size",category:"ob",subcategory:"Ovaries",ranges:[{label:"Normal (premenopausal)",unit:"volume",notes:"≤10 mL (L\xd7W\xd7H\xd70.52)"},{label:"Postmenopausal",unit:"volume",notes:"≤4 mL — larger may need follow-up"}],clinicalNote:"Volume = 0.52 \xd7 L \xd7 W \xd7 H. Asymmetry >1.5\xd7 should be noted. Dominant follicle normal up to 2.5 cm.",tags:["ovary","ovaries","follicle","cyst","postmenopausal"]},{id:"ob-gest-sac",name:"Gestational Sac (1st Trimester)",category:"ob",subcategory:"First Trimester",ranges:[{label:"Visible on TVUS",unit:"GA",notes:"~4.5–5 weeks (MSD ≥5 mm)"},{label:"Yolk sac visible",unit:"GA",notes:"~5.5 weeks (MSD ≥8 mm)"},{label:"Embryo + cardiac activity",unit:"GA",notes:"~6 weeks (CRL ~5 mm)"}],clinicalNote:"MSD ≥25 mm without embryo = anembryonic pregnancy (blighted ovum). Always confirm on follow-up if borderline.",tags:["gestational sac","msd","first trimester","early pregnancy","ob"]},{id:"ob-crl",name:"Crown-Rump Length (CRL)",category:"ob",subcategory:"First Trimester",ranges:[{label:"6 weeks",unit:"approx",notes:"~5 mm"},{label:"8 weeks",unit:"approx",notes:"~16 mm"},{label:"10 weeks",unit:"approx",notes:"~31 mm"},{label:"12 weeks",unit:"approx",notes:"~55 mm"},{label:"13 weeks",unit:"approx",notes:"~70 mm"}],clinicalNote:"Most accurate dating 7–13 weeks. Machine calculates GA automatically. Measure longest axis, neutral position.",tags:["crl","crown-rump","first trimester","dating","ob"]},{id:"ob-nt",name:"Nuchal Translucency (NT)",category:"ob",subcategory:"First Trimester",ranges:[{max:3,unit:"mm",label:"Normal (11–13+6 weeks)"},{min:3,unit:"mm",label:"Increased — Down syndrome / cardiac defect risk",notes:"Refer for genetic counseling"}],clinicalNote:"CRL must be 45–84 mm. Neutral head position, image magnified. Calipers on inner edge of each line. AIUM certified exam.",tags:["nuchal","nt","downs","trisomy","first trimester","screening"]},{id:"ob-bpd",name:"Biparietal Diameter (BPD)",category:"ob",subcategory:"Second/Third Trimester",ranges:[{label:"18 weeks",unit:"approx",notes:"~44 mm"},{label:"20 weeks",unit:"approx",notes:"~50 mm"},{label:"24 weeks",unit:"approx",notes:"~61 mm"},{label:"28 weeks",unit:"approx",notes:"~72 mm"},{label:"32 weeks",unit:"approx",notes:"~83 mm"},{label:"36 weeks",unit:"approx",notes:"~92 mm"},{label:"40 weeks",unit:"approx",notes:"~97 mm"}],clinicalNote:"Measure outer-to-inner at widest point (thalami + CSP visible, no cerebellum). Part of EFW biometry.",tags:["bpd","biparietal","ob","biometry","second trimester"]},{id:"ob-fl",name:"Femur Length (FL)",category:"ob",subcategory:"Second/Third Trimester",ranges:[{label:"18 weeks",unit:"approx",notes:"~28 mm"},{label:"20 weeks",unit:"approx",notes:"~34 mm"},{label:"24 weeks",unit:"approx",notes:"~44 mm"},{label:"28 weeks",unit:"approx",notes:"~53 mm"},{label:"32 weeks",unit:"approx",notes:"~62 mm"},{label:"36 weeks",unit:"approx",notes:"~70 mm"},{label:"40 weeks",unit:"approx",notes:"~78 mm"}],clinicalNote:"Measure the ossified diaphysis only — exclude epiphyses. The transducer should be perpendicular to the femur.",tags:["femur","fl","ob","biometry","second trimester","growth"]},{id:"amniotic-fluid",name:"Amniotic Fluid Index (AFI)",category:"ob",subcategory:"Fluid Assessment",ranges:[{min:8,max:24,unit:"cm",label:"Normal AFI"},{min:5,max:7.9,unit:"cm",label:"Borderline oligohydramnios"},{max:5,unit:"cm",label:"Oligohydramnios",notes:"Or MVP <2 cm — consider delivery"},{min:24,unit:"cm",label:"Polyhydramnios",notes:"Or MVP >8 cm — GDM, fetal anomaly"}],clinicalNote:"Sum of deepest vertical pocket in all 4 quadrants. Single Deepest Pocket (SDP/MVP) >2 cm is alternative method.",tags:["afi","amniotic fluid","oligohydramnios","polyhydramnios","ob"]},{id:"cervical-length",name:"Cervical Length (TVUS)",category:"ob",subcategory:"Cervix",ranges:[{min:30,unit:"mm",label:"Normal (16–24 weeks)"},{min:20,max:29,unit:"mm",label:"Short cervix — progesterone therapy"},{max:20,unit:"mm",label:"Very short — preterm birth risk",notes:"Consult MFM"}],clinicalNote:"Transvaginal. Bladder empty. Measure internal to external os, linear canal. Three images, shortest measurement reported.",tags:["cervix","cervical length","preterm","incompetent cervix","ob"]},{id:"thyroid-lobe-volume",name:"Thyroid Lobe Volume",category:"thyroid",subcategory:"Thyroid",ranges:[{label:"Normal female",unit:"mL",notes:"4–8 mL per lobe (total <18 mL)"},{label:"Normal male",unit:"mL",notes:"5–10 mL per lobe (total <25 mL)"}],clinicalNote:"Volume = L \xd7 W \xd7 H \xd7 0.52 per lobe. Isthmus usually ≤3–5 mm AP. Goiter: total volume >18 mL (F) or >25 mL (M).",tags:["thyroid","volume","goiter","lobe"]},{id:"thyroid-nodule",name:"Thyroid Nodule Characterization",category:"thyroid",subcategory:"Nodules",ranges:[{label:"ACR TI-RADS 1: 0 pts",unit:"risk",notes:"Benign — no biopsy needed"},{label:"ACR TI-RADS 2: 0 pts",unit:"risk",notes:"Not suspicious — no biopsy"},{label:"ACR TI-RADS 3: 3 pts",unit:"risk",notes:"Mildly suspicious — FNA if ≥2.5 cm"},{label:"ACR TI-RADS 4: 4–6 pts",unit:"risk",notes:"Moderately suspicious — FNA if ≥1.5 cm"},{label:"ACR TI-RADS 5: ≥7 pts",unit:"risk",notes:"Highly suspicious — FNA if ≥1 cm"}],clinicalNote:"Score based on: composition, echogenicity, shape, margin, echogenic foci. Report: size (3 dimensions), location, vascularity.",tags:["thyroid","nodule","tirads","fnab","biopsy","cancer"]},{id:"aortic-root",name:"Aortic Root Diameter",category:"cardiac",subcategory:"Aorta",ranges:[{max:3.7,unit:"cm",label:"Normal (women)"},{max:4,unit:"cm",label:"Normal (men)"},{min:4,unit:"cm",label:"Dilated — Marfan / bicuspid AV concern",notes:"Monitor annually"}],clinicalNote:"Measure at sinus of Valsalva (inner edge method, at end-diastole). Body surface area indexing preferred.",tags:["aortic root","cardiac","echo","marfan","aorta"]},{id:"lv-ef",name:"Left Ventricular Ejection Fraction (LVEF)",category:"cardiac",subcategory:"LV Function",ranges:[{min:55,unit:"%",label:"Normal (≥55%)"},{min:41,max:54,unit:"%",label:"Mildly reduced (HFmrEF)"},{min:36,max:40,unit:"%",label:"Moderately reduced"},{max:35,unit:"%",label:"Severely reduced (HFrEF)",notes:"ICD consideration"}],clinicalNote:"Biplane Simpson's method preferred (A4C + A2C). Visual estimate acceptable in poor windows. Report as range.",tags:["ef","ejection fraction","lv","heart failure","cardiac","echo"]},{id:"ivc-diameter",name:"IVC Diameter / Collapsibility",category:"cardiac",subcategory:"Volume Status",ranges:[{max:2.1,unit:"cm",label:"Normal IVC diameter"},{label:">50% collapse with sniff",unit:"collapse",notes:"CVP ≤5 mmHg — euvolemic/hypovolemic"},{label:"<50% collapse with sniff",unit:"collapse",notes:"CVP ≥10 mmHg — elevated RA pressure"}],clinicalNote:"Subcostal view, measure 1–2 cm from RA junction, in M-mode. POCUS essential skill.",tags:["ivc","inferior vena cava","cvp","volume","pocus","cardiac"]},{id:"prostate-volume",name:"Prostate Volume & Dimensions",category:"abdomen",subcategory:"Prostate",ranges:[{max:30,unit:"mL",label:"Normal",notes:"AP ≤3.0 cm \xb7 Width ≤4.5 cm \xb7 Length ≤4.0 cm"},{min:30,max:50,unit:"mL",label:"Mild BPH",notes:"Correlate with symptoms (IPSS score)"},{min:50,max:80,unit:"mL",label:"Moderate BPH",notes:"Medical therapy usually indicated"},{min:80,unit:"mL",label:"Severe BPH / Large Prostate",notes:"Surgical intervention often required"}],clinicalNote:"Volume = AP \xd7 Width \xd7 Length \xd7 0.52 (ellipsoid formula). Measure transabdominal with full bladder (routine) or transrectal US (TRUS) for greater accuracy. PSA density = PSA (ng/mL) \xf7 Volume (mL) — density >0.15 ng/mL/mL raises cancer concern. Always document AP, width, and length in 3 planes.",tags:["prostate","bph","prostate volume","benign prostatic hyperplasia","psa","urinary retention","abdomen","men"]},{id:"prostate-ap-width-length",name:"Prostate Dimensions (3-Plane)",category:"abdomen",subcategory:"Prostate",ranges:[{max:3,unit:"cm",label:"Normal AP diameter (anterior-posterior)"},{max:4.5,unit:"cm",label:"Normal width (transverse)"},{max:4,unit:"cm",label:"Normal length (cranio-caudal)"}],clinicalNote:"AP measured in sagittal (transverse diameter), width in transverse (widest), length from base to apex in sagittal. Calcifications: echogenic foci in transition zone — benign, common in older men. Peripheral zone hypoechoic nodule: PCa concern — recommend TRUS \xb1 biopsy.",tags:["prostate","dimensions","ap","width","length","measurement","men","abdomen"]},{id:"uterus-ap-width",name:"Uterus — AP & Width Dimensions",category:"ob",subcategory:"Uterus",ranges:[{min:3,max:5,unit:"cm",label:"Normal AP diameter (anterior-posterior)",notes:"Measured in sagittal at widest point"},{min:4,max:6,unit:"cm",label:"Normal width (transverse)",notes:"Measured at widest transverse dimension"}],clinicalNote:"AP measured in sagittal plane at body of uterus (not fundus, not cervix). Width measured in axial/transverse plane. Postmenopausal: AP 2–4 cm, width 3–5 cm. Enlarged uterus (>9 cm length or >5 cm AP): consider fibroids, adenomyosis, or malignancy.",tags:["uterus","ap","width","dimensions","uterine","gynecology","ob"]},{id:"uterus-postmenopausal",name:"Uterus — Postmenopausal Size",category:"ob",subcategory:"Uterus",ranges:[{min:3.5,max:6.5,unit:"cm",label:"Normal postmenopausal length"},{min:2,max:4,unit:"cm",label:"Normal postmenopausal AP"},{min:2.5,max:5,unit:"cm",label:"Normal postmenopausal width"}],clinicalNote:"Uterus atrophies after menopause. Endometrium ≤4 mm (no HRT) is normal. Any uterine enlargement in postmenopausal patient warrants further evaluation. Fibroids may regress but calcified ones persist.",tags:["uterus","postmenopausal","atrophy","size","gynecology","ob"]},{id:"ue-arterial-velocities",name:"Upper Extremity Arterial PSV",category:"vascular",subcategory:"Upper Extremity",ranges:[{min:60,max:120,unit:"cm/s",label:"Normal subclavian PSV",notes:"Triphasic waveform expected"},{min:50,max:100,unit:"cm/s",label:"Normal brachial PSV",notes:"Triphasic waveform"},{min:40,max:90,unit:"cm/s",label:"Normal radial / ulnar PSV",notes:"Triphasic waveform"}],clinicalNote:"All normal UE arteries should have triphasic waveform (high resistance). Monophasic waveform distal to a stenosis = hemodynamically significant obstruction proximal. Bilateral brachial pressure difference >15 mmHg = subclavian or innominate stenosis on low-pressure side.",tags:["upper extremity","arterial","psv","subclavian","brachial","radial","ulnar","vascular"]},{id:"av-fistula-flow-volume",name:"AV Fistula Flow Volume",category:"vascular",subcategory:"Dialysis Access",ranges:[{max:499,unit:"mL/min",label:"Inadequate flow — risk of poor dialysis",notes:"Assess for stenosis"},{min:500,max:1200,unit:"mL/min",label:"Adequate for dialysis",notes:"Target range for most centers"},{min:1200,max:2e3,unit:"mL/min",label:"High flow — acceptable, monitor",notes:"May indicate maturation or upstream dilation"},{min:2e3,unit:"mL/min",label:"Very high flow — cardiac risk / steal",notes:"Consider banding or reduction"}],clinicalNote:"Measure at brachial artery: Volume (mL/min) = π \xd7 (diameter/2)\xb2 \xd7 TAMEAN \xd7 60. Mature AVF target: ≥600 mL/min. Very high flow (>2000 mL/min): risk of high-output cardiac failure or arterial steal syndrome.",tags:["av fistula","flow volume","dialysis","avf","hemodialysis","access","vascular"]},{id:"supraspinatus-thickness",name:"Supraspinatus Tendon Thickness",category:"musculoskeletal",subcategory:"Shoulder",ranges:[{min:5.5,max:7.5,unit:"mm",label:"Normal AP thickness (critical zone)"},{min:4,max:5.4,unit:"mm",label:"Thinned — partial-thickness or chronic tear"},{max:4,unit:"mm",label:"Significantly thinned — full-thickness tear concern"}],clinicalNote:'Measure at the "critical zone" — 1 cm proximal to greater tuberosity insertion. Hypoechoic defect = tear. Compare to contralateral side. Use 12–15 MHz linear probe.',tags:["supraspinatus","rotator cuff","shoulder","tendon","msk","tear"]},{id:"achilles-tendon-thickness",name:"Achilles Tendon AP Thickness",category:"musculoskeletal",subcategory:"Ankle/Foot",ranges:[{max:6,unit:"mm",label:"Normal (measured 2–6 cm above insertion)"},{min:6,max:8,unit:"mm",label:"Borderline — mild tendinopathy"},{min:8,unit:"mm",label:"Tendinopathy — thickened, hypoechoic",notes:"Assess for neovascularity on Doppler"}],clinicalNote:"Measure 2–6 cm proximal to calcaneal insertion (non-insertional). Insertional tendinopathy: measure at bone attachment. Ruptured tendon: gap between fiber ends — measure retraction distance.",tags:["achilles","tendon","ankle","msk","tendinopathy","rupture"]},{id:"plantar-fascia-thickness",name:"Plantar Fascia Thickness",category:"musculoskeletal",subcategory:"Ankle/Foot",ranges:[{max:4,unit:"mm",label:"Normal (calcaneal origin)"},{min:4,max:6,unit:"mm",label:"Thickened — plantar fasciitis"},{min:6,unit:"mm",label:"Severely thickened — advanced fasciitis or tear risk"}],clinicalNote:"Measure in longitudinal view at calcaneal origin. Look for hypoechoic change, neovascularity, and calcaneal spur. Partial tear: focal anechoic defect in thickened fascia.",tags:["plantar fascia","plantar fasciitis","heel","msk","foot pain","calcaneus"]},{id:"median-nerve-csa",name:"Median Nerve Cross-Sectional Area (CSA)",category:"musculoskeletal",subcategory:"Wrist/Hand",ranges:[{max:9,unit:"mm\xb2",label:"Normal at carpal tunnel inlet (pisiform level)"},{min:10,max:14,unit:"mm\xb2",label:"Mild CTS — enlarged nerve"},{min:15,unit:"mm\xb2",label:"Moderate-severe CTS",notes:"Clinical correlation with EMG/NCS"}],clinicalNote:"Trace nerve outline at proximal carpal tunnel (pisiform level) in axial view. Wrist:forearm ratio >1.4 is also diagnostic. Look for flattening of nerve within tunnel.",tags:["median nerve","carpal tunnel","cts","wrist","msk","nerve","neuropathy"]},{id:"patellar-tendon-thickness",name:"Patellar Tendon Thickness",category:"musculoskeletal",subcategory:"Knee",ranges:[{max:7,unit:"mm",label:"Normal AP thickness (proximal tendon)"},{min:7,max:10,unit:"mm",label:"Mild tendinopathy"},{min:10,unit:"mm",label:'Significant tendinopathy ("jumper\'s knee")'}],clinicalNote:"Measure at inferior pole of patella (most common site). Loss of fibrillar pattern + hypoechogenicity = tendinopathy. Partial or complete tear: focal anechoic defect.",tags:["patellar tendon","knee","jumper knee","msk","tendinopathy","patella"]},{id:"joint-effusion",name:"Joint Effusion (Knee)",category:"musculoskeletal",subcategory:"Knee",ranges:[{max:3,unit:"mm",label:"None to trace (normal)"},{min:3,max:10,unit:"mm",label:"Small effusion"},{min:10,unit:"mm",label:"Moderate–large effusion",notes:"Consider aspiration if >1 cm"}],clinicalNote:"Measure suprapatellar pouch in longitudinal view, suprapatellar area with knee extended or in slight flexion (30\xb0). Simple effusion: anechoic. Complex effusion (echoes/debris): consider infection, hemarthrosis, crystal arthritis.",tags:["joint effusion","knee","msk","suprapatellar","arthritis","aspiration"]},{id:"hip-effusion",name:"Hip Joint Effusion",category:"musculoskeletal",subcategory:"Hip",ranges:[{max:5,unit:"mm",label:"Normal anterior capsule-to-neck distance (adults)"},{min:5,unit:"mm",label:"Effusion present (or >2 mm asymmetry vs contralateral hip)",notes:"Pediatric: >2 mm asymmetry = aspiration consideration"}],clinicalNote:"Anterior longitudinal view: measure between anterior joint capsule and femoral neck. Compare bilateral. Pediatric transient synovitis vs septic arthritis: ultrasound cannot distinguish — clinical correlation (fever, WBC, CRP) required.",tags:["hip effusion","hip","msk","joint effusion","pediatric","transient synovitis","septic arthritis"]},{id:"biceps-tendon",name:"Biceps Tendon (Long Head)",category:"musculoskeletal",subcategory:"Shoulder",ranges:[{min:3,max:6,unit:"mm",label:"Normal diameter in bicipital groove"},{min:6,unit:"mm",label:"Thickened — tendinopathy or tenosynovitis",notes:"Fluid in sheath: >1–2 mm = tenosynovitis"}],clinicalNote:"Scan in transverse in bicipital groove. Fluid in sheath — assess for tendon instability (medial subluxation or dislocation on shoulder internal rotation). Absent tendon = complete rupture.",tags:["biceps","bicipital","shoulder","msk","tendon","groove","tenosynovitis"]},{id:"common-extensor-tendon",name:"Common Extensor Tendon (Lateral Elbow)",category:"musculoskeletal",subcategory:"Elbow",ranges:[{min:4,max:7,unit:"mm",label:"Normal thickness at lateral epicondyle origin"},{min:7,unit:"mm",label:'Thickened — lateral epicondylosis ("tennis elbow")',notes:"Hypoechoic = enthesopathy"}],clinicalNote:"Scan in longitudinal at lateral epicondyle. Tendinopathy: hypoechoic, thickened, calcifications, neovascularity on Doppler. Partial tear: focal anechoic defect. Full tear: discontinuity — surgical evaluation.",tags:["common extensor tendon","tennis elbow","lateral epicondylitis","elbow","msk","tendinopathy"]},{id:"common-flexor-tendon",name:"Common Flexor Tendon (Medial Elbow)",category:"musculoskeletal",subcategory:"Elbow",ranges:[{min:4,max:7,unit:"mm",label:"Normal thickness at medial epicondyle origin"},{min:7,unit:"mm",label:'Thickened — medial epicondylosis ("golfer\'s elbow")',notes:"Hypoechoic = enthesopathy"}],clinicalNote:"Scan in longitudinal at medial epicondyle. Associated with UCL (ulnar collateral ligament) injury — evaluate UCL integrity. Ulnar nerve: assess in cubital tunnel for enlargement or subluxation.",tags:["common flexor tendon","golfer elbow","medial epicondylitis","elbow","msk","tendinopathy"]},{id:"lv-dimensions",name:"LV End-Diastolic / Systolic Dimensions",category:"cardiac",subcategory:"LV Function",ranges:[{min:3.9,max:5.3,unit:"cm",label:"Normal LVIDd (women)"},{min:4.2,max:5.9,unit:"cm",label:"Normal LVIDd (men)"},{min:6,unit:"cm",label:"Dilated LV — cardiomyopathy concern",notes:"Confirm with biplane EF"}],clinicalNote:"Measure by M-mode at mitral leaflet tips level in PLAX. Normal LVIDs (systolic): women 2.2–4.0 cm, men 2.5–4.0 cm. Fractional shortening (FS) = (LVIDd − LVIDs)/LVIDd \xd7 100% — normal ≥25%.",tags:["lv","lvid","left ventricle","cardiac","echo","cardiomyopathy","dimensions"]},{id:"wall-thickness-echo",name:"LV Wall Thickness (IVS + LVPW)",category:"cardiac",subcategory:"LV Function",ranges:[{min:.6,max:1,unit:"cm",label:"Normal IVSd and LVPWd"},{min:1,max:1.3,unit:"cm",label:"Mildly increased — early LVH"},{min:1.3,max:1.6,unit:"cm",label:"Moderately increased — LVH"},{min:1.6,unit:"cm",label:"Severe — HOCM or infiltrative disease",notes:"Consider cardiac MRI"}],clinicalNote:"Measure IVSd (interventricular septum) and LVPWd (LV posterior wall) at end-diastole in PLAX. Wall thickness ≥15 mm: consider HOCM, amyloid, or Fabry disease.",tags:["lvh","wall thickness","ivs","lvpw","cardiac","echo","hocm","hypertrophy"]},{id:"left-atrium-size",name:"Left Atrial Diameter / Volume",category:"cardiac",subcategory:"Atria",ranges:[{max:4,unit:"cm",label:"Normal LA diameter (PLAX)"},{min:4,max:4.6,unit:"cm",label:"Mildly dilated"},{min:4.6,max:5.2,unit:"cm",label:"Moderately dilated — atrial fibrillation/diastolic dysfunction"},{min:5.2,unit:"cm",label:"Severely dilated",notes:"LA volume index >34 mL/m\xb2 = dilation"}],clinicalNote:"Diameter: measured in PLAX at systole (between posterior aortic wall and posterior LA wall). Volume index = LA volume \xf7 BSA. Enlarged LA: chronic AF, mitral valve disease, diastolic dysfunction.",tags:["left atrium","la","atrium","cardiac","echo","atrial fibrillation","diastolic dysfunction"]},{id:"rv-systolic-pressure",name:"Estimated RVSP (Pulmonary HTN)",category:"cardiac",subcategory:"Right Heart",ranges:[{max:35,unit:"mmHg",label:"Normal estimated RVSP"},{min:36,max:50,unit:"mmHg",label:"Mild pulmonary hypertension concern"},{min:50,unit:"mmHg",label:"Moderate-severe PH — pulmonology referral",notes:"RHC for definitive diagnosis"}],clinicalNote:"RVSP = 4 \xd7 (TR Vmax)\xb2 + estimated RAP. TR Vmax by CW Doppler. RAP estimated from IVC: ≤8 mmHg if IVC ≤2.1 cm and collapses >50%; 15 mmHg if dilated IVC with <50% collapse.",tags:["rvsp","pulmonary hypertension","tr velocity","rv","cardiac","echo","pulmonary"]},{id:"mitral-valve-inflow",name:"Mitral Valve Inflow (E/A Ratio)",category:"cardiac",subcategory:"Diastolic Function",ranges:[{min:.8,max:2,unit:"ratio",label:"Normal E/A ratio (age-variable)"},{max:.8,unit:"ratio",label:"Impaired relaxation (Grade I diastolic dysfunction)"},{min:2,unit:"ratio",label:"Restrictive filling (Grade III) — elevated filling pressures",notes:"High filling pressures — urgent HF evaluation"}],clinicalNote:"PW Doppler at mitral leaflet tips (A4C). E = early passive filling, A = late atrial filling. E/A 0.8–2.0 + elevated E/e' = Grade II (pseudonormal). Tissue Doppler (e') at septal mitral annulus: normal ≥7 cm/s; lateral ≥10 cm/s.",tags:["mitral","e/a ratio","diastolic dysfunction","cardiac","echo","heart failure","filling pressure"]},{id:"aortic-valve-area",name:"Aortic Valve Area (AVA)",category:"cardiac",subcategory:"Valves",ranges:[{min:2.5,unit:"cm\xb2",label:"Normal"},{min:1.5,max:2.5,unit:"cm\xb2",label:"Mild AS"},{min:1,max:1.5,unit:"cm\xb2",label:"Moderate AS"},{max:1,unit:"cm\xb2",label:"Severe AS",notes:"<0.6 cm\xb2 = very severe — urgent referral"}],clinicalNote:"Continuity equation: AVA = (LVOT area \xd7 LVOT VTI) \xf7 AV VTI. Peak AV velocity severe AS ≥4 m/s. Mean gradient severe ≥40 mmHg. Low-flow state can underestimate — dobutamine stress echo if needed.",tags:["aortic valve","ava","aortic stenosis","cardiac","echo","gradient","tavr"]},{id:"pericardial-effusion-size",name:"Pericardial Effusion Size",category:"cardiac",subcategory:"Pericardium",ranges:[{max:5,unit:"mm",label:"Small effusion (< 5 mm behind LV in PLAX)"},{min:5,max:20,unit:"mm",label:"Moderate effusion"},{min:20,unit:"mm",label:"Large effusion — assess for tamponade physiology",notes:"RA/RV collapse = tamponade"}],clinicalNote:"Measure posterior LV in PLAX during diastole. Also assess: RA collapse (diastole), RV collapse (diastole), IVC collapsibility. Loculated post-surgical effusions may not be posterior — look in all windows.",tags:["pericardial effusion","tamponade","pericarditis","cardiac","echo","pericardium","pocus"]},{id:"ob-hc",name:"Head Circumference (HC)",category:"ob",subcategory:"Second/Third Trimester",ranges:[{label:"18 weeks",unit:"approx",notes:"~161 mm"},{label:"20 weeks",unit:"approx",notes:"~188 mm"},{label:"24 weeks",unit:"approx",notes:"~234 mm"},{label:"28 weeks",unit:"approx",notes:"~272 mm"},{label:"32 weeks",unit:"approx",notes:"~305 mm"},{label:"36 weeks",unit:"approx",notes:"~332 mm"},{label:"40 weeks",unit:"approx",notes:"~351 mm"}],clinicalNote:"Measure outer edge to outer edge at widest biparietal diameter level (thalami + CSP, no cerebellum). Trace or use electronic calipers. Part of 4-measurement EFW along with BPD, AC, FL.",tags:["hc","head circumference","ob","biometry","second trimester","growth","efw"]},{id:"ob-ac",name:"Abdominal Circumference (AC)",category:"ob",subcategory:"Second/Third Trimester",ranges:[{label:"18 weeks",unit:"approx",notes:"~133 mm"},{label:"20 weeks",unit:"approx",notes:"~158 mm"},{label:"24 weeks",unit:"approx",notes:"~204 mm"},{label:"28 weeks",unit:"approx",notes:"~248 mm"},{label:"32 weeks",unit:"approx",notes:"~291 mm"},{label:"36 weeks",unit:"approx",notes:"~326 mm"},{label:"40 weeks",unit:"approx",notes:"~367 mm"}],clinicalNote:"Most sensitive biometric parameter for IUGR. Measure at level of portal-umbilical vein junction (liver), stomach bubble visible, spine at 3 or 9 o'clock. Circular or elliptical fetal abdomen. Small AC: consider IUGR, diabetes if large.",tags:["ac","abdominal circumference","ob","biometry","iugr","fetal growth","second trimester"]},{id:"ob-efw",name:"Estimated Fetal Weight (EFW)",category:"ob",subcategory:"Second/Third Trimester",ranges:[{label:"SGA (<10th %ile for GA)",unit:"category",notes:"Small for gestational age — IUGR concern"},{label:"AGA (10th–90th %ile)",unit:"category",notes:"Appropriate for gestational age — normal"},{label:"LGA (>90th %ile)",unit:"category",notes:"Large for gestational age — GDM, macrosomia"}],clinicalNote:"Hadlock formula uses BPD, HC, AC, FL (\xb15–15% margin of error). SGA: serial biometry every 2–3 weeks. AC <5th percentile is most predictive of IUGR. Macrosomia: EFW >4000g or >90th percentile.",tags:["efw","estimated fetal weight","ob","iugr","macrosomia","growth restriction","biometry"]},{id:"ob-mca-doppler",name:"MCA PSV (Fetal Anemia Screening)",category:"ob",subcategory:"Fetal Doppler",ranges:[{max:1.5,unit:"MoM",label:"Normal MCA PSV (<1.5 MoM for GA)"},{min:1.5,unit:"MoM",label:"Elevated — moderate-severe fetal anemia concern",notes:"Refer for fetal blood sampling"}],clinicalNote:"Middle cerebral artery PSV (angle = 0\xb0). >1.5 MoM (multiples of median for GA) predicts moderate-severe fetal anemia with 88% sensitivity. Used in Rh disease, TTTS, hydrops. Normal value increases with GA — use GA-specific tables.",tags:["mca","middle cerebral artery","fetal anemia","ob","doppler","rh disease","hydrops","isoimmunization"]},{id:"ob-umbilical-artery-doppler",name:"Umbilical Artery Doppler (S/D Ratio)",category:"ob",subcategory:"Fetal Doppler",ranges:[{label:"Normal S/D ratio",unit:"GA-dependent",notes:"Decreases with advancing GA (>28 wks: S/D <3.0 expected)"},{label:"Absent end-diastolic flow (AEDF)",unit:"abnormal",notes:"IUGR — consider delivery discussion with MFM"},{label:"Reversed end-diastolic flow (REDF)",unit:"critical",notes:"Imminent fetal compromise — urgent MFM/delivery"}],clinicalNote:"Sample umbilical artery free loop. Angle-independent: use S/D ratio or RI. Normal trend: EDV increases as GA advances (ratio falls). AEDF/REDF = severe placental insufficiency — highest urgency in IUGR surveillance.",tags:["umbilical artery","doppler","iugr","ob","fetal surveillance","s/d ratio","redf","aedf","placental insufficiency"]},{id:"ob-ductus-venosus",name:"Ductus Venosus (DV) Waveform",category:"ob",subcategory:"Fetal Doppler",ranges:[{label:"Normal: positive a-wave",unit:"waveform",notes:"Forward flow throughout cardiac cycle"},{label:"Abnormal: absent/reversed a-wave",unit:"waveform",notes:"Severe cardiac compromise — delivery consideration"}],clinicalNote:"Sample DV (small vessel from umbilical vein to IVC) in sagittal view, at inlet. Used in 11–13 week NT screening (reversed a-wave = cardiac/chromosomal defect risk) and IUGR surveillance (worsening DV = delivery trigger).",tags:["ductus venosus","dv","ob","doppler","iugr","fetal surveillance","first trimester","nt"]},{id:"lymph-node-size",name:"Lymph Node Size (Short Axis)",category:"superficial",subcategory:"Lymph Nodes",ranges:[{max:10,unit:"mm",label:"Normal short axis (most sites)"},{max:15,unit:"mm",label:"Normal jugulodigastric node (subdigastric)",notes:"Jugulodigastric up to 15 mm normal"},{min:10,unit:"mm",label:"Enlarged — requires characterization (hilum, shape, vascularity)",notes:"Round + absent hilum = suspicious"}],clinicalNote:"Short axis >10 mm at most sites is abnormal. Malignant features: round shape (L:S ratio <2), absent fatty hilum, peripheral or chaotic vascularity, cystic necrosis. Any suspicious node should be correlated with clinical context and FNA considered.",tags:["lymph node","lymphadenopathy","neck","axilla","groin","superficial","malignancy"]},{id:"thyroid-isthmus",name:"Thyroid Isthmus Thickness",category:"thyroid",subcategory:"Thyroid",ranges:[{max:5,unit:"mm",label:"Normal AP thickness"},{min:5,unit:"mm",label:"Thickened isthmus — Hashimoto's, goiter, or mass",notes:"Assess for isthmus nodule"}],clinicalNote:"Measure AP in transverse midline. Enlarged isthmus: thyroiditis, isthmus goiter. Any discrete nodule in isthmus: apply TI-RADS criteria (same as lobe nodules). Isthmus nodules can cause dysphagia/stridor earlier due to central location.",tags:["thyroid","isthmus","hashimoto","goiter","thyroid nodule","tiRads"]},{id:"parotid-submandibular-gland",name:"Salivary Gland Dimensions",category:"superficial",subcategory:"Salivary Glands",ranges:[{label:"Parotid gland",unit:"size",notes:"Length 3.5–5 cm; AP 1.5–3 cm; homogeneous, isoechoic to fat"},{label:"Submandibular gland",unit:"size",notes:"Length 3–4 cm; AP 1.5–2.5 cm; homogeneous"}],clinicalNote:"Enlarged parotid: infection (parotitis — increased vascularity), Sj\xf6gren's (heterogeneous), sarcoid, HIV. Ductal calculus: shadowing stone, dilated duct. Mass within: pleomorphic adenoma (most common benign), Warthin's tumor (bilateral posterior parotid), mucoepidermoid carcinoma (malignant).",tags:["parotid","submandibular","salivary gland","superficial","neck","mass","stone"]}];function l(e){if(!e.trim())return o;let a=e.toLowerCase();return o.filter(e=>{var i,t;return e.name.toLowerCase().includes(a)||e.tags.some(e=>e.toLowerCase().includes(a))||(null===(i=e.subcategory)||void 0===i?void 0:i.toLowerCase().includes(a))||(null===(t=e.clinicalNote)||void 0===t?void 0:t.toLowerCase().includes(a))})}}}]);